#include <iostream>
#include <string>

class LandVehicle {
    int speed_;
public:
    explicit LandVehicle(int s) : speed_{s} {}
    int speed() const { return speed_; }
};

class WaterVehicle {
    int depth_;
public:
    explicit WaterVehicle(int d) : depth_{d} {}
    int depth() const { return depth_; }
};

class Amphibious : public LandVehicle, public WaterVehicle {
public:
    Amphibious(int s, int d) : LandVehicle{s}, WaterVehicle{d} {}
    void describe() const {
        std::cout << "amphibious: speed=" << speed() << " depth=" << depth() << "\n";
    }
};

int main() {
    int s{}, d{};
    std::cin >> s >> d;
    Amphibious a{s, d};

    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string q;
        std::cin >> q;
        if (q == "land") {
            std::cout << "land speed: " << a.speed() << "\n";
        } else if (q == "water") {
            std::cout << "water depth: " << a.depth() << "\n";
        } else if (q == "describe") {
            a.describe();
        }
    }
    return 0;
}

